  "inlineSchema": "// ============================================================\n//  HEART SCHEMA — Banco mestre multi-tenant\n//  Gerencia tenants (empresas) e usuários globais\n// ============================================================\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  output        = \"../src/generated/heart-client\"\n  binaryTargets = [\"native\", \"linux-musl-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL_HEART\")\n}\n\n// ------------------------------------------------------------\n//  Tenant — dados completos da empresa emitente (NFC-e)\n// ------------------------------------------------------------\nmodel Tenant {\n  id           String  @id @default(uuid())\n  databaseName String  @unique @map(\"database_name\")\n  databaseUrl  String  @map(\"database_url\")\n  name         String  @default(\"\") // nome legado (mantém compatibilidade)\n  status       String  @default(\"active\") // active, suspended, inactive\n  logoUrl      String?\n  modulos      Json?   @default(\"{\\\"nfce\\\": true, \\\"estoque\\\": true, \\\"dashboardMobile\\\": true}\")\n\n  // Identificação\n  razaoSocial  String?\n  nomeFantasia String?\n  cnpj         String? @unique\n  ie           String? // Inscrição Estadual\n  im           String? // Inscrição Municipal\n  crt          Int     @default(1) // 1=Simples Nacional, 2=SN Excesso, 3=Regime Normal\n\n  // Endereço\n  logradouro    String?\n  numero        String?\n  complemento   String?\n  bairro        String?\n  municipio     String?\n  codMunicipio  String? // Código IBGE (7 dígitos) ex: \"3506003\" para Bauru-SP\n  uf            String?\n  cep           String?\n  telefone      String?\n  emailContador String?\n\n  // NFC-e — configurações de emissão\n  nfceAtivo    Boolean @default(false) // habilita emissão NFC-e\n  nfceAutoSync Boolean @default(true) // habilita o CRON de retentativa para este tenant\n  nfceSerie    Int     @default(1) // série (ex: 1)\n  nfceAmbiente Int     @default(2) // 1=Produção, 2=Homologação\n  nfceCsc      String? // Código de Segurança do Contribuinte (SEFAZ)\n  nfceIdCsc    String? // ID do CSC\n\n  // Certificado Digital A1\n  certPfx      Bytes? // .pfx armazenado como BLOB\n  certSenha    String? // senha do certificado\n  certValidade DateTime? // data de vencimento\n\n  // Integração Cosmos (Bluesoft) — lookup de EAN brasileiro\n  cosmosApiKey String? // Token da API Cosmos do cliente para lookup de EAN\n\n  // Mensalidades\n  mensalidadeValor      Decimal?  @default(0.00) @map(\"mensalidade_valor\") @db.Decimal(10, 2)\n  mensalidadeVencimento DateTime? @map(\"mensalidade_vencimento\")\n\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n  termsAcceptedAt DateTime? @map(\"terms_accepted_at\")\n\n  users User[]\n\n  @@map(\"tenants\")\n}\n\n// ------------------------------------------------------------\n//  User — usuários vinculados ao tenant\n// ------------------------------------------------------------\nmodel User {\n  id       String @id @default(uuid())\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  name     String\n  email    String  @unique\n  password String\n  role     String  @default(\"operator\") // admin, manager, operator\n  pin      String? // PIN de 4-6 dígitos para troca rápida no PDV\n  active   Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"users\")\n}\n\n// ------------------------------------------------------------\n//  MasterProduct — dicionário global de produtos por EAN\n//  Compartilhado entre todos os tenants (banco heart)\n//  Usado para auto-preenchimento ao bipar código de barras\n// ------------------------------------------------------------\nmodel MasterProduct {\n  id       String  @id @default(uuid())\n  ean      String  @unique // EAN-13 (13 dígitos)\n  name     String // Nome comercial padronizado (PT-BR)\n  brand    String? // Marca (ex: Heineken, Ambev)\n  ncm      String? // NCM 8 dígitos — obrigatório NFC-e\n  cest     String? // CEST 7 dígitos — quando há ST\n  unit     String  @default(\"UN\") // UN, LT, FD, CX, KG\n  imageUrl String? @db.Text // URL da foto do produto\n  category String? // Categoria OFF (ex: en:beers)\n  source   String  @default(\"openfoodfacts\") // rastreabilidade da origem\n\n  createdAt DateTime @default(now())\n\n  @@index([ean])\n  @@map(\"master_products\")\n}\n\n// ------------------------------------------------------------\n//  Image — armazenamento global de fotos no banco heart\n// ------------------------------------------------------------\nmodel Image {\n  id        String   @id @default(uuid())\n  data      Bytes    @db.LongBlob\n  mimeType  String\n  createdAt DateTime @default(now())\n\n  @@map(\"images\")\n}\n",
